def _allow_request() -> bool:
    key = _rate_limit_key()
    now = time.time()
    capacity = max(1, SETTINGS.max_concurrent)
    refill_rate = capacity / 1.0
    tokens, last = _token_bucket.get(key, (capacity, now))
    elapsed = now - last
    tokens = min(capacity, tokens + elapsed * refill_rate)
    if tokens < 1.0:
        _token_bucket[key] = (tokens, now)
        return False
    tokens -= 1.0
    _token_bucket[key] = (tokens, now)
    return True


