    url = data.get("url") or request.args.get("url")
    variant = (data.get("variant") or request.args.get("variant") or "thumb").strip().lower()
    force = str(data.get("force") or request.args.get("force") or "").lower() in ("1", "true", "yes")
    return_inline = str(data.get("inline") or request.args.get("inline") or "").lower() in ("1", "true", "yes")

    try:
        url = _normalize_url(url)
        _validate_url(url)
    except ValueError as e:
        return _json_error(str(e), 400, "invalid_url")

    if variant not in ("thumb", "full"):
        return _json_error("variant must be thumb or full", 400, "invalid_variant")

    key = _key_for(url, variant)

    if not force and _s3_head_object(key):
        resp = {
            "ok": True,
            "url": url,
            "variant": variant,
            "s3": {"bucket": SETTINGS.s3_bucket, "key": key},
            "image_url": _s3_url_for(key),
            "cached": True,
            "content_type": _content_type(),
        }
        return jsonify(resp)

    try:
        png = _capture_png_bytes(url)
        if variant == "thumb":
            out_bytes = _make_thumbnail(png)
        else:
            img = Image.open(io.BytesIO(png)).convert("RGB")
            out = io.BytesIO()
            fmt = "JPEG" if SETTINGS.image_format in ("jpeg", "jpg") else SETTINGS.image_format.upper()
            save_kwargs = {}
            if fmt == "JPEG":
                save_kwargs.update({"quality": SETTINGS.jpeg_quality, "optimize": True, "progressive": True})
            elif fmt == "WEBP":
                save_kwargs.update({"quality": SETTINGS.jpeg_quality, "method": 6})
            img.save(out, format=fmt, **save_kwargs)
            out_bytes = out.getvalue()

        _s3_put_object(key, out_bytes, _content_type())

        if return_inline:
            return Response(out_bytes, status=200, mimetype=_content_type(), headers={"Cache-Control": "no-store"})

        resp = {
            "ok": True,
            "url": url,
            "variant": variant,
            "s3": {"bucket": SETTINGS.s3_bucket, "key": key},
            "image_url": _s3_url_for(key),
            "cached": False,
            "content_type": _content_type(),
        }
        return jsonify(resp)
    except TimeoutError:
        return _json_error("timeout rendering page", 504, "timeout")
    except WebDriverException as e:
        logger.exception("webdriver error")
        return _json_error(f"render failed: {str(e)}", 502, "render_failed")
    except Exception as e:
        logger.exception("unexpected error")
        return _json_error(f"unexpected error: {str(e)}", 500, "server_error")


